namespace sv_d170e8f3c5b84d149adc9afb52cce512.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = new();

    public IReadOnlyList<CartItem> Items => _items.AsReadOnly();

    public int TotalCount => _items.Sum(i => i.Quantity);

    public decimal TotalPrice => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(int id, string name, decimal price)
    {
        var existing = _items.FirstOrDefault(i => i.Id == id);
        if (existing is not null)
        {
            existing.Quantity++;
        }
        else
        {
            _items.Add(new CartItem { Id = id, Name = name, Price = price, Quantity = 1 });
        }
        OnChange?.Invoke();
    }

    public void Remove(int id)
    {
        var item = _items.FirstOrDefault(i => i.Id == id);
        if (item is not null)
        {
            _items.Remove(item);
            OnChange?.Invoke();
        }
    }

    public void Clear()
    {
        _items.Clear();
        OnChange?.Invoke();
    }
}

@using sv_d170e8f3c5b84d149adc9afb52cce512.Services
@inject CartState Cart
@implements IDisposable

<NavLink class="nav-link" href="cart">
    <span class="bi bi-cart-nav-menu" aria-hidden="true"></span> Cart
    @if (Cart.TotalCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@Cart.TotalCount</span>
    }
</NavLink>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

@page "/products"
@using sv_d170e8f3c5b84d149adc9afb52cce512.Services
@inject CartState Cart

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4 mt-2">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Description</p>
                    <p class="card-text fw-bold">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private record Product(int Id, string Name, string Description, decimal Price);

    private readonly List<Product> _products = new()
    {
        new(1, "Wireless Mouse", "Ergonomic wireless mouse with USB receiver", 29.99m),
        new(2, "Mechanical Keyboard", "RGB backlit mechanical keyboard", 79.99m),
        new(3, "USB-C Hub", "7-in-1 USB-C multiport adapter", 49.99m),
        new(4, "Webcam HD", "1080p HD webcam with built-in microphone", 59.99m),
        new(5, "Monitor Stand", "Adjustable aluminum monitor riser", 39.99m),
        new(6, "Laptop Sleeve", "Water-resistant 15-inch laptop sleeve", 24.99m),
    };

    private void AddToCart(Product product)
    {
        Cart.Add(product.Id, product.Name, product.Price);
    }
}

@page "/cart"
@using sv_d170e8f3c5b84d149adc9afb52cce512.Services
@inject CartState CartState
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Shopping Cart</h1>

@if (!CartState.Items.Any())
{
    <p class="mt-3">Your cart is empty. <a href="products">Browse products</a>.</p>
}
else
{
    <table class="table mt-3">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in CartState.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-sm btn-danger" @onclick="() => Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end fw-bold">Total:</td>
                <td class="fw-bold">@CartState.TotalPrice.ToString("C")</td>
                <td></td>
            </tr>
        </tfoot>
    </table>

    <button class="btn btn-outline-danger" @onclick="CartState.Clear">Clear Cart</button>
}

@code {
    protected override void OnInitialized()
    {
        CartState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        CartState.OnChange -= StateHasChanged;
    }
}

